26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const PROCESSING_FEE = 5;
37	const BLOCK_SIZE = 3;
38	const BLOCK_PRICE = 60;
39	const CURSED_SURCHARGE_RATE = 0.5;
40	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
41	
42	const calculateQuotePremium = (items: Item[], customer: { yearsWithMHPCO: number }, quoteIndex: number): number => {
43	  let basePremium = 0;
44	  let itemSurcharges = 0;
45	  const componentCounts: Record<string, number> = {};
46	
47	  for (const item of items) {
48	    if (COMPONENT_TYPES.has(item.type)) {
49	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
50	    } else {
51	      const itemBasePremium = BASE_PREMIUMS[item.type];
52	      basePremium += itemBasePremium;
53	      if (item.cursed) {
54	        itemSurcharges += itemBasePremium * CURSED_SURCHARGE_RATE;
55	      }
56	      if (item.enchantment >= 5) {
57	        itemSurcharges += itemBasePremium * 0.3;
58	      }
59	    }
60	  }
61	
62	  for (const [type, count] of Object.entries(componentCounts)) {
63	    basePremium += count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUMS[type];
64	  }
65	
66	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
67	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
68	  const followUpDiscount = quoteIndex > 0 ? basePremium * 0.15 : 0;
69	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
70	};
71	
72	export const processScenario = (scenario: Scenario): ScenarioResult => {
73	  let quoteCount = 0;
74	  const results = scenario.steps.map((step) => {
75	    const result = {
76	      premium: calculateQuotePremium(step.items, scenario.customer, quoteCount),
77	    };
78	    quoteCount++;
79	    return result;
80	  });
81	  return { results };
82	};
